import { memo } from 'react';
import { 
  Brain, 
  FileSearch, 
  FilePen, 
  Terminal, 
  Check, 
  AlertCircle, 
  Info,
  Loader2,
  ChevronRight,
  MessageSquare,
  ListTodo
} from 'lucide-react';
import { ChatMarkdown } from './ChatMarkdown';

// Timeline row types (inspired by T3 Code)
export type TimelineRowType = 
  | 'work'           // Activity/tool execution
  | 'message'        // Assistant response
  | 'proposed-plan'  // Plan steps (not executing yet)
  | 'working';       // Animated working indicator

export type WorkTone = 
  | 'thinking' 
  | 'file_read' 
  | 'file_write' 
  | 'command' 
  | 'tool' 
  | 'info' 
  | 'error';

export interface WorkEntry {
  id: string;
  tone: WorkTone;
  label: string;
  detail?: string;
  status?: 'running' | 'completed' | 'failed';
}

export interface TimelineRowProps {
  type: TimelineRowType;
  // For 'work' type
  entries?: WorkEntry[];
  // For 'message' type
  content?: string;
  isStreaming?: boolean;
  // For 'proposed-plan' type
  steps?: string[];
}

// Get Tailwind classes for work entry styling
export function workToneClass(tone: WorkTone): {
  border: string;
  bg: string;
  text: string;
  icon: string;
} {
  switch (tone) {
    case 'thinking':
      return {
        border: 'border-purple-500/30',
        bg: 'bg-purple-500/5',
        text: 'text-purple-300',
        icon: 'text-purple-400',
      };
    case 'file_read':
      return {
        border: 'border-blue-500/30',
        bg: 'bg-blue-500/5',
        text: 'text-blue-300',
        icon: 'text-blue-400',
      };
    case 'file_write':
      return {
        border: 'border-emerald-500/30',
        bg: 'bg-emerald-500/5',
        text: 'text-emerald-300',
        icon: 'text-emerald-400',
      };
    case 'command':
      return {
        border: 'border-amber-500/30',
        bg: 'bg-amber-500/5',
        text: 'text-amber-300',
        icon: 'text-amber-400',
      };
    case 'error':
      return {
        border: 'border-red-500/30',
        bg: 'bg-red-500/5',
        text: 'text-red-300',
        icon: 'text-red-400',
      };
